import React, { useState, useEffect } from "react";
import { useParams } from "react-router-dom";
import { fetchMatches, createAssignment } from "../utils/api";
import { UrgencyBadge, StatusBadge } from "../components/Badges";
import { getInitials, getAvatarStyle, URGENCY_COLORS } from "../utils/helpers";
import LoadingSpinner from "../components/LoadingSpinner";
import { toast } from "react-toastify";

export default function MatchingPage({ needs, onAssign }) {
  const { needId } = useParams();
  const [selectedNeed, setSelectedNeed] = useState(null);
  const [matches, setMatches] = useState([]);
  const [loading, setLoading] = useState(false);

  const activeNeeds = [...needs]
    .filter((n) => n.status !== "completed" && n.status !== "rejected")
    .sort((a, b) => b.priorityScore - a.priorityScore);

  useEffect(() => {
    if (needId) {
      const found = activeNeeds.find((n) => n.id === needId);
      if (found) setSelectedNeed(found);
    } else if (activeNeeds.length > 0 && !selectedNeed) {
      setSelectedNeed(activeNeeds[0]);
    }
  }, [activeNeeds, needId, selectedNeed]);

  useEffect(() => {
    if (!selectedNeed) return;
    setLoading(true);
    fetchMatches(selectedNeed.id)
      .then((res) => setMatches(res.data.data || []))
      .catch(() => setMatches([]))
      .finally(() => setLoading(false));
  }, [selectedNeed]);

  const handleAssign = async (volunteerId) => {
    if (selectedNeed?.volunteerId || selectedNeed?.status === "in-progress") {
      if (!window.confirm("This need already has a volunteer assigned. Replace them with this volunteer?")) return;
    }
    try {
      await createAssignment({ volunteerId, needId: selectedNeed.id });
      toast.success("Volunteer assigned successfully!");
      if (onAssign) onAssign();
      const res = await fetchMatches(selectedNeed.id);
      setMatches(res.data.data || []);
    } catch {
      toast.error("Failed to assign volunteer");
    }
  };

  return (
    <div className="grid-2">
      <div className="card">
        <div className="section-title">Select need to match ({activeNeeds.length})</div>
        {activeNeeds.length === 0 && <p style={{ color: "#94a3b8", fontSize: 13 }}>No active needs.</p>}
        {activeNeeds.map((n) => (
          <div
            key={n.id}
            className="need-row"
            style={{
              cursor: "pointer",
              background: selectedNeed?.id === n.id ? "#f8fafc" : "",
              borderRadius: 8,
              padding: "8px 6px",
              transition: "background 0.15s",
            }}
            onClick={() => setSelectedNeed(n)}
          >
            <div style={{ minWidth: 44, textAlign: "center" }}>
              <div style={{ fontSize: 18, fontWeight: 700, color: URGENCY_COLORS[n.urgency], fontFamily: "monospace" }}>
                {n.priorityScore}
              </div>
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13, fontWeight: 500 }}>{n.title}</div>
              <div style={{ display: "flex", gap: 4, marginTop: 3, alignItems: "center" }}>
                <UrgencyBadge urgency={n.urgency} />
                <StatusBadge status={n.status} />
                {(n.volunteerId || n.status === "in-progress") && (
                  <span style={{ fontSize: 10, color: "#166534", fontWeight: 600, background: "#dcfce7", padding: "1px 6px", borderRadius: 10, display: "inline-flex", alignItems: "center", gap: 3 }}>
                    👥 1 Assigned
                  </span>
                )}
              </div>
            </div>
            <div style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace" }}>{n.peopleAffected}p</div>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="section-title">
          Volunteer matches {selectedNeed ? `— ${selectedNeed.title.slice(0, 22)}...` : ""}
        </div>
        {loading && <LoadingSpinner message="Finding matches..." />}
        {!loading && !selectedNeed && <p style={{ color: "#94a3b8", fontSize: 13 }}>Select a need on the left.</p>}
        {!loading && selectedNeed && matches.length === 0 && (
          <p style={{ color: "#94a3b8", fontSize: 13 }}>No available volunteers match this need's skills and location right now.</p>
        )}
        {!loading && matches.map((v, i) => {
          const style = getAvatarStyle(i);
          return (
            <div key={v.id} className="match-row">
              <div className="score-circle" style={{
                background: v.matchScore > 70 ? "#dcfce7" : v.matchScore > 40 ? "#fef9c3" : "#fee2e2",
                color: v.matchScore > 70 ? "#166534" : v.matchScore > 40 ? "#854d0e" : "#991b1b",
              }}>
                {v.matchScore}%
              </div>
              <div className="vol-avatar" style={{ width: 34, height: 34, fontSize: 12, background: style.bg, color: style.color }}>
                {getInitials(v.name)}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 13, fontWeight: 500 }}>{v.name}</div>
                <div style={{ display: "flex", gap: 3, flexWrap: "wrap", marginTop: 2 }}>
                  {v.skills.map((s) => (
                    <span key={s} className="skill-tag" style={{
                      color: (v.matchedSkills || []).includes(s) ? "#166534" : "#94a3b8",
                      background: (v.matchedSkills || []).includes(s) ? "#dcfce7" : "#f8fafc",
                    }}>{s}</span>
                  ))}
                </div>
                <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2, fontFamily: "monospace" }}>{v.distance}km away</div>
              </div>
              <button className="btn btn-sm btn-primary" onClick={() => handleAssign(v.id)}>Assign ✓</button>
            </div>
          );
        })}
        {!loading && matches.length > 0 && (
          <div style={{ marginTop: 12, padding: "8px 10px", background: "#f8fafc", borderRadius: 8, fontSize: 12, color: "#64748b" }}>
            Scoring: skill overlap (40%) + location proximity (60%). Green = direct skill match.
          </div>
        )}
      </div>
    </div>
  );
}
